      MECHANICAL: { base: "2D+1", skills: {} },
      PERCEPTION: { base: "4D", skills: { "bargain": "4D+2", "con": "6D", "con: seduction": "10D+2", "investigation": "5D", "persuasion": "7D", "gambling": "5D" } },
