      KNOWLEDGE: { base: "2D", skills: { "alien species": "4D", "bureaucracy": "4D+2", "business: casino": "6D" } },
      MECHANICAL: { base: "2D", skills: {} },
      PERCEPTION: { base: "2D", skills: { "command": "3D+2", "gambling": "4D" } },
      STRENGTH: { base: "2D", skills: { "brawling": "4D+1" } },
