      KNOWLEDGE: { base: "3D", skills: { "bureaucracy: Imperial fleet": "4D", "planetary systems": "3D+1" } },
      MECHANICAL: { base: "3D+2", skills: { "capital ship piloting": "4D" } },
      PERCEPTION: { base: "3D+1", skills: { "bargain": "5D+1", "command": "4D+1", "sneak": "4D" } },
      STRENGTH: { base: "2D+1", skills: { "brawling": "3D+2", "stamina": "3D+1" } },
