      PERCEPTION: { base: "3D", skills: { bargain: "8D", command: "6D", con: "8D", forgery: "5D", "forgery: ship IDs": "7D", gambling: "8D", hide: "8D", persuasion: "5D", search: "5D+2", sneak: "4D+2" } },
