    specialAbilities: "Cybernetic Improvement: Modified NeuroSaav Hifold Sensory Package cybernetic eye. Increases Perception and all related skills by +2D (not reflected in listed stats). No attempt made to disguise the implant.",
    forcePoints: 1,
    darkSidePoints: 3,
    characterPoints: 15,
    move: 10,
