      STRENGTH: { base: "3D", skills: { brawling: "5D", stamina: "5D" } },
      TECHNICAL: { base: "3D", skills: { "armor repair": "4D", demolitions: "4D", "hover vehicle repair": "4D+1", security: "4D", "walker repair": "5D" } }
