      KNOWLEDGE: { base: "3D", skills: { "alien species": "5D+1", "bureaucracy": "8D", "bureaucracy: Imperial Navy procedures": "9D+1", "business": "8D+1", "business: mining": "11D+2", "business administration": "8D", "cultures": "7D+1", "languages": "6D", "planetary systems": "5D+2", "streetwise": "9D", "survival": "6D+2", "survival: urban": "8D", "tactics: capital ships": "5D", "tactics: starfighters": "6D", "value": "7D", "willpower": "6D+1" } },
      MECHANICAL: { base: "2D+1", skills: { "archaic starship piloting": "5D+1", "astrogation": "7D", "communications": "6D", "ground vehicle operation": "5D+1", "hover vehicle operation": "5D+1", "repulsorlift operation": "5D+2", "sensors": "5D+2", "space transports": "9D", "starfighter piloting": "9D", "starship gunnery": "8D", "starship shields": "8D+1", "swoop operation": "5D+1" } },
