      PERCEPTION: { base: "4D", skills: { "bargain": "11D", "command": "10D", "command: New Republic bureaucrats": "10D+1", "command: New Republic soldiers": "11D+1", "con": "9D", "gambling": "6D", "hide": "6D+2", "persuasion": "8D", "persuasion: debate": "10D+1", "persuasion: oration": "11D", "search": "7D", "sneak": "4D+2" } },
