      PERCEPTION: { base: "3D+1", skills: { "bargain": "5D+1", "command": "10D+2", "con": "5D+1", "gambling": "4D+2", "hide": "6D+1", "persuasion": "5D", "search": "7D", "sneak": "6D+1", "sneak: forest": "6D+2" } },
