      TECHNICAL: { base: "4D", skills: { "(A) capital ship engineering": "6D", "capital ship repair": "10D", "(A) capital ship weapon engineering": "5D", "capital ship weapon repair": "7D+2", "computer programming/repair": "7D+1", "droid programming": "7D+2", "droid repair": "6D+2", "(A) repulsorlift engineering": "8D", "repulsorlift repair": "9D+1", "security": "5D", "starfighter repair": "6D+2", "(A) World Devastator factory engineering": "9D", "(A) World Devastator factory programming": "9D+2" } }
