      STRENGTH: { base: "3D", skills: { "brawling": "4D", "stamina": "4D" } },
      TECHNICAL: { base: "2D+2", skills: { "computer programming/repair": "5D+1", "droid programming": "3D", "droid repair": "3D+2", "space transports repair": "5D+1", "starship weapon repair": "4D+1" } }
